import './CategorywiseExpenseChart.css';
import {
    PieChart,
    Pie,
    Tooltip,
    Legend,
    ResponsiveContainer
} from "recharts";

function CategorywiseExpenseChart({categoryData}) {
    const pieChartData = Object.entries(categoryData).map(
        ([category, amount]) => ({
            category,
            amount
        })
    );
    return (
        <ResponsiveContainer
            width="100%"
            height={350}
        >
            <PieChart>

                <Pie
                    data={pieChartData}
                    dataKey="amount"
                    nameKey="category"
                    outerRadius={120}
                    label
                />

                <Tooltip />

                <Legend />

            </PieChart>
        </ResponsiveContainer>
    );
}
export default CategorywiseExpenseChart;
